import { tags } from 'decantr/tags';
import { createSignal, onMount } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, icon } from 'decantr/components';

code.example:
function ChatThread({ messages, isTyping, onLoadMore, hasMore }) {
  const { div, span } = tags;
  const [showScrollBtn, setShowScrollBtn] = createSignal(false);
  let containerRef;

  const scrollToBottom = () => {
    containerRef?.scrollTo({ top: containerRef.scrollHeight, behavior: 'smooth' });
  };

  const handleScroll = (e) => {
    const { scrollTop, scrollHeight, clientHeight } = e.target;
    setShowScrollBtn(scrollHeight - scrollTop - clientHeight > 100);
  };

  onMount(() => scrollToBottom());

  return div({ class: css('_flex _col _hfull _overflow[hidden] _relative') },
    div({ 
      ref: (el) => containerRef = el,
      class: css('_flex1 _overflow[auto] _p6 _flex _col _gap2'),
      onscroll: handleScroll
    },
      hasMore ? div({ class: css('_flex _jcc _py4') },
        Button({ variant: 'ghost', size: 'sm', onclick: onLoadMore },
          icon('chevron-up'), 'Load earlier messages'
        )
      ) : null,
      ...messages.map(m => ChatMessage({ message: m, variant: m.role })),
      isTyping ? div({ class: css('_flex _aic _gap2 _py2') },
        span({ class: css('carbon-skeleton _w8 _h8 _rfull') }),
        span({ class: css('_fgmuted _textsm') }, 'AI is thinking...')
      ) : null
    ),
    showScrollBtn() ? Button({
      variant: 'outline',
      size: 'sm',
      class: css('_absolute _bottom20 _right6 _shadow'),
      onclick: scrollToBottom
    }, icon('chevron-down')) : null
  );
}

