function BranchedThread({ messages, branchPoint, branches }) {
  const { div, span } = tags;

  return div({ class: css('_flex _col _hfull _overflow[hidden]') },
    branchPoint ? div({ class: css('_flex _aic _gap2 _px6 _py2 _bgmuted/5 _borderB') },
      icon('git-branch', { size: '14', class: css('_fgmuted') }),
      span({ class: css('_textsm _fgmuted') }, `Branched from message ${branchPoint}`),
      branches.length > 1 ? Button({ variant: 'ghost', size: 'xs' },
        `${branches.length} branches`, icon('chevron-down')
      ) : null
    ) : null,
    div({ class: css('_flex1 _overflow[auto] _p6 _flex _col _gap2') },
      ...messages.map(m => ChatMessage({ message: m, variant: m.role }))
    )
  );
}

